1	// ABOUTME: Chat panel UI module — rich markdown rendering of ACP agent conversations.
2	// ABOUTME: Manages chat tabs, WebSocket connections, streaming text, and tool call cards.
3	
4	(function () {
5	  "use strict";
6	
7	  // --- Markdown setup ---
8	  marked.setOptions({
9	    highlight: function (code, lang) {
10	      if (lang && hljs.getLanguage(lang)) {
11	        return hljs.highlight(code, { language: lang }).value;
12	      }
13	      return hljs.highlightAuto(code).value;
14	    },
15	    breaks: true,
16	    gfm: true,
17	  });
18	
19	  // --- State ---
20	  var chatTabs = {};
21	  var activeChatTabId = null;
22	  var chatTabIdCounter = 0;
23	
24	  // --- DOM refs ---
25	  var $chatPanel = document.getElementById("chat-panel");
26	  var $chatTabs = document.getElementById("chat-tabs");
27	  var $chatMessages = document.getElementById("chat-messages");
28	  var $chatInput = document.getElementById("chat-input");
29	  var $chatSend = document.getElementById("chat-send");
30	  var $chatClose = document.getElementById("chat-close");
31	  var $chatCost = document.getElementById("chat-cost");
32	  var $viewToggle = document.getElementById("view-toggle");
33	
34	  // --- Helpers ---
35	
36	  function escapeHtml(s) {
37	    var div = document.createElement("div");
38	    div.textContent = s;
39	    return div.innerHTML;
40	  }
41	
42	  function renderMarkdown(text) {
43	    return DOMPurify.sanitize(marked.parse(text || ""));
44	  }
45	
46	  function generateChatTabId() {
47	    return "chat-" + (chatTabIdCounter++);
48	  }
49	
50	  function scrollToBottom() {
51	    if (!$chatMessages) return;
52	    $chatMessages.scrollTop = $chatMessages.scrollHeight;
53	  }
54	
55	  // --- Tool call icons by kind ---
56	  var TOOL_ICONS = {
57	    read: "&#128196;",     // page
58	    edit: "&#9998;",       // pencil
59	    execute: "&#9654;",    // play
60	    search: "&#128269;",   // magnifier
61	    "delete": "&#128465;", // trash
62	    think: "&#128161;",    // lightbulb
63	    fetch: "&#127760;",    // globe
64	  };
65	
66	  // --- Tab Management ---
67	
68	  function renderChatTabs() {
69	    $chatTabs.innerHTML = "";
70	    Object.keys(chatTabs).forEach(function (tabId) {
71	      var tab = chatTabs[tabId];
72	      var el = document.createElement("div");
73	      el.className = "chat-tab" + (tabId === activeChatTabId ? " active" : "");
74	      el.innerHTML =
75	        '<span class="chat-tab-title">' + escapeHtml(tab.title) + "</span>" +
76	        '<span class="chat-tab-close">&times;</span>';
77	
78	      el.querySelector(".chat-tab-title").addEventListener("click", function () {
79	        switchChatTab(tabId);
80	      });
81	      el.querySelector(".chat-tab-close").addEventListener("click", function (e) {
82	        e.stopPropagation();
83	        closeChatTab(tabId);
84	      });
85	      $chatTabs.appendChild(el);
86	    });
87	  }
88	
89	  function switchChatTab(tabId) {
90	    if (!chatTabs[tabId]) return;
91	    if (activeChatTabId && chatTabs[activeChatTabId]) {
92	      chatTabs[activeChatTabId].container.classList.remove("active");
93	    }
94	    activeChatTabId = tabId;
95	    chatTabs[tabId].container.classList.add("active");
96	    renderChatTabs();
97	    scrollToBottom();
98	    $chatInput.focus();
99	  }
100	
101	  function closeChatTab(tabId) {
102	    var tab = chatTabs[tabId];
103	    if (!tab) return;
104	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
105	      tab.ws.close();
106	    }
107	    if (tab.container && tab.container.parentNode) {
108	      tab.container.parentNode.removeChild(tab.container);
109	    }
110	    delete chatTabs[tabId];
111	
112	    var remaining = Object.keys(chatTabs);
113	    if (remaining.length > 0) {
114	      switchChatTab(remaining[remaining.length - 1]);
115	    } else {
116	      activeChatTabId = null;
117	      $chatPanel.classList.add("hidden");
118	      document.body.classList.remove("chat-open");
119	    }
120	    renderChatTabs();
121	  }
122	
123	  // --- Chat Tab Creation ---
124	
125	  function createChatTab(title, agent, cwd, existingSessionId, sessionSummary) {
126	    var tabId = generateChatTabId();
127	
128	    var container = document.createElement("div");
129	    container.className = "chat-tab-container";
130	    $chatMessages.appendChild(container);
131	
132	    var tabData = {
133	      id: tabId,
134	      ws: null,
135	      sessionId: null,
136	      agent: agent,
137	      cwd: cwd,
138	      container: container,
139	      title: title,
140	      streaming: false,
141	      currentTextAccum: "",
142	      currentTextEl: null,
143	      thinkingAccum: "",
144	      thinkingEl: null,
145	      renderScheduled: false,
146	      sessionSummary: sessionSummary || null,
147	    };
148	    chatTabs[tabId] = tabData;
149	
150	    // Show panel
151	    $chatPanel.classList.remove("hidden");
152	    document.body.classList.add("chat-open");
153	
154	    // Hide previous active tab
155	    if (activeChatTabId && chatTabs[activeChatTabId]) {
156	      chatTabs[activeChatTabId].container.classList.remove("active");
157	    }
158	    activeChatTabId = tabId;
159	    container.classList.add("active");
160	
161	    renderChatTabs();
162	    connectWebSocket(tabData, existingSessionId);
163	    $chatInput.focus();
164	
165	    return tabId;
166	  }
167	
168	  // --- WebSocket ---
169	
170	  function connectWebSocket(tabData, sessionId) {
171	    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
172	    var wsUrl = wsProtocol + "//" + location.host + "/ws/chat";
173	    var ws = new WebSocket(wsUrl);
174	    tabData.ws = ws;
175	
176	    ws.onopen = function () {
177	      ws.send(JSON.stringify({
178	        type: "start",
179	        agent: tabData.agent,
180	        cwd: tabData.cwd,
181	        sessionId: sessionId || undefined,
182	      }));
183	    };
184	
185	    ws.onmessage = function (evt) {
186	      try {
187	        var msg = JSON.parse(evt.data);
188	        handleServerMessage(tabData, msg);
189	      } catch (e) {
190	        console.error("Failed to parse chat message:", e);
191	      }
192	    };
193	
194	    ws.onclose = function () {
195	      tabData.streaming = false;
196	      updateInputState();
197	    };
198	
199	    ws.onerror = function () {
200	      appendSystemMessage(tabData, "Connection error");
201	    };
202	  }
203	
204	  // --- Message Routing ---
205	
206	  function handleServerMessage(tabData, msg) {
207	    switch (msg.type) {
208	      case "session_init":
209	        tabData.sessionId = msg.sessionId;
210	        if (msg.agentInfo) {
211	          appendSystemMessage(tabData, msg.agentInfo.title + " connected");
212	        }
213	        if (!msg.historyLoaded && tabData.sessionSummary) {
214	          appendInfoBanner(tabData, "Previous messages not available. " + tabData.sessionSummary);
215	        }
216	        break;
217	
218	      case "update":
219	        handleUpdate(tabData, msg);
220	        break;
221	
222	      case "turn_complete":
223	        finalizeAssistantMessage(tabData);
224	        tabData.streaming = false;
225	        updateInputState();
226	        break;
227	
228	      case "error":
229	        appendSystemMessage(tabData, "Error: " + (msg.message || "Unknown error"));
230	        tabData.streaming = false;
231	        updateInputState();
232	        break;
233	
234	      case "auth_required":
235	        appendAuthBanner(tabData, msg);
236	        break;
237	
238	      default:
239	        console.log("Unknown chat message type:", msg.type);
240	    }
241	  }
242	
243	  function handleUpdate(tabData, msg) {
244	    var su = msg.sessionUpdate;
245	    switch (su) {
246	      case "agent_message_chunk":
247	        var text = (msg.content && msg.content.text) || "";
248	        if (text) appendAgentText(tabData, text);
249	        break;
250	
251	      case "agent_thought_chunk":
252	        var thought = (msg.content && msg.content.text) || "";
253	        if (thought) appendThinking(tabData, thought);
254	        break;
255	
256	      case "user_message_chunk":
257	        var userText = (msg.content && msg.content.text) || "";
258	        if (userText) appendUserBubble(tabData, userText);
259	        break;
260	
261	      case "tool_call":
262	        renderToolCall(tabData, msg);
263	        break;
264	
265	      case "tool_call_update":
266	        updateToolCall(tabData, msg);
267	        break;
268	
269	      case "usage_update":
270	        renderUsage(msg);
271	        break;
272	
273	      case "plan":
274	        renderPlan(tabData, msg.entries || []);
275	        break;
276	
277	      default:
278	        // Gracefully ignore unknown update types
279	        break;
280	    }
281	  }
282	
283	  // --- Rendering: User Messages ---
284	
285	  function appendUserBubble(tabData, text) {
286	    // Close any open agent message
287	    finalizeAssistantMessage(tabData);
288	
289	    var bubble = document.createElement("div");
290	    bubble.className = "chat-bubble user";
291	    bubble.textContent = text;
292	    tabData.container.appendChild(bubble);
293	    scrollToBottom();
294	  }
295	
296	  // --- Rendering: Agent Text (streaming) ---
297	
298	  function appendAgentText(tabData, text) {
299	    // Close thinking if open
300	    finalizeThinking(tabData);
301	
302	    tabData.currentTextAccum += text;
303	    if (!tabData.currentTextEl) {
304	      var bubble = document.createElement("div");
305	      bubble.className = "chat-bubble assistant";
306	      var content = document.createElement("div");
307	      content.className = "chat-md-content";
308	      bubble.appendChild(content);
309	      tabData.container.appendChild(bubble);
310	      tabData.currentTextEl = content;
311	    }
312	    scheduleRender(tabData);
313	  }
314	
315	  function scheduleRender(tabData) {
316	    if (tabData.renderScheduled) return;
317	    tabData.renderScheduled = true;
318	    requestAnimationFrame(function () {
319	      tabData.renderScheduled = false;
320	      if (tabData.currentTextEl) {
321	        tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
322	      }
323	      scrollToBottom();
324	    });
325	  }
326	
327	  function finalizeAssistantMessage(tabData) {
328	    if (tabData.currentTextEl && tabData.currentTextAccum) {
329	      tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
330	    }
331	    tabData.currentTextEl = null;
332	    tabData.currentTextAccum = "";
333	    finalizeThinking(tabData);
334	  }
335	
336	  // --- Rendering: Thinking ---
337	
338	  function appendThinking(tabData, text) {
339	    tabData.thinkingAccum += text;
340	    if (!tabData.thinkingEl) {
341	      var block = document.createElement("details");
342	      block.className = "chat-thinking";
343	      block.innerHTML = "<summary>Thinking...</summary><div class='chat-thinking-content'></div>";
344	      tabData.container.appendChild(block);
345	      tabData.thinkingEl = block.querySelector(".chat-thinking-content");
346	    }
347	    tabData.thinkingEl.textContent = tabData.thinkingAccum;
348	    scrollToBottom();
349	  }
350	
351	  function finalizeThinking(tabData) {
352	    tabData.thinkingEl = null;
353	    tabData.thinkingAccum = "";
354	  }
355	
356	  // --- Rendering: Tool Calls ---
357	
358	  function renderToolCall(tabData, tc) {
359	    // Close thinking
360	    finalizeThinking(tabData);
361	
362	    var card = document.createElement("details");
363	    card.className = "chat-tool-card";
364	    card.setAttribute("data-tool-id", tc.toolCallId || "");
365	
366	    var status = tc.status || "pending";
367	    var kind = tc.kind || "other";
368	    var icon = TOOL_ICONS[kind] || "&#128295;"; // wrench default
369	    var title = tc.title || "Tool call";
370	    var locationText = "";
371	    if (tc.locations && tc.locations.length > 0) {
372	      var loc = tc.locations[0];
373	      var path = (loc && loc.path) || "";
374	      locationText = '<span class="chat-tool-path">' + escapeHtml(path.split("/").pop()) + "</span>";
375	    }
376	
377	    card.innerHTML =
378	      '<summary class="chat-tool-header">' +
379	        '<span class="chat-tool-icon">' + icon + "</span>" +
380	        '<span class="chat-tool-title">' + escapeHtml(title) + "</span>" +
381	        locationText +
382	        '<span class="chat-tool-status ' + escapeHtml(status) + '">' + escapeHtml(status) + "</span>" +
383	      "</summary>" +
384	      '<div class="chat-tool-body"></div>';
385	
386	    tabData.container.appendChild(card);
387	    scrollToBottom();
388	  }
389	
390	  function updateToolCall(tabData, update) {
391	    var card = tabData.container.querySelector(
392	      '.chat-tool-card[data-tool-id="' + (update.toolCallId || "") + '"]'
393	    );
394	    if (!card) return;
395	
396	    // Update status badge
397	    if (update.status) {
398	      var badge = card.querySelector(".chat-tool-status");
399	      if (badge) {
400	        badge.textContent = update.status;
401	        badge.className = "chat-tool-status " + update.status;
402	      }
403	    }
404	
405	    // Append content
406	    if (update.content && update.content.length > 0) {
407	      var body = card.querySelector(".chat-tool-body");
408	      if (body) {
409	        update.content.forEach(function (item) {
410	          if (item.type === "diff") {
411	            renderDiff(body, item);
412	          } else if (item.type === "content" && item.content) {
413	            var text = item.content.text || "";
414	            if (text) {
415	              var pre = document.createElement("pre");
416	              pre.className = "chat-tool-output";
417	              pre.textContent = text.length > 2000 ? text.substring(0, 2000) + "\n...(truncated)" : text;
418	              body.appendChild(pre);
419	            }
420	          }
421	        });
422	      }
423	    }
424	    scrollToBottom();
425	  }
426	
427	  function renderDiff(container, diff) {
428	    var el = document.createElement("div");
429	    el.className = "chat-diff";
430	    var header = document.createElement("div");
431	    header.className = "chat-diff-header";
432	    header.textContent = diff.path || "file";
433	    el.appendChild(header);
434	
435	    var pre = document.createElement("pre");
436	    pre.className = "chat-diff-content";
437	    // Simple diff display: show newText (the result)
438	    pre.textContent = diff.newText || "";
439	    el.appendChild(pre);
440	    container.appendChild(el);
441	  }
442	
443	  // --- Rendering: Plan ---
444	
445	  function renderPlan(tabData, entries) {
446	    // Remove any existing plan
447	    var existing = tabData.container.querySelector(".chat-plan");
448	    if (existing) existing.parentNode.removeChild(existing);
449	
450	    if (!entries.length) return;
451	
452	    var el = document.createElement("div");
453	    el.className = "chat-plan";
454	    el.innerHTML = "<div class='chat-plan-title'>Plan</div>";
455	    var list = document.createElement("ul");
456	    entries.forEach(function (entry) {
457	      var li = document.createElement("li");
458	      var statusIcon = entry.status === "completed" ? "&#10003;" : entry.status === "failed" ? "&#10007;" : "&#9744;";
459	      li.innerHTML = '<span class="chat-plan-icon">' + statusIcon + '</span> ' + escapeHtml(entry.content || "");
460	      li.className = "chat-plan-entry " + (entry.status || "pending");
461	      list.appendChild(li);
462	    });
463	    el.appendChild(list);
464	    tabData.container.appendChild(el);
465	    scrollToBottom();
466	  }
467	
468	  // --- Rendering: Usage ---
469	
470	  function renderUsage(msg) {
471	    if (!$chatCost) return;
472	    var cost = msg.cost;
473	    if (cost && cost.amount != null) {
474	      $chatCost.textContent = "$" + cost.amount.toFixed(4);
475	      $chatCost.classList.remove("hidden");
476	    }
477	  }
478	
479	  // --- Rendering: System / Info / Auth ---
480	
481	  function appendSystemMessage(tabData, text) {
482	    var el = document.createElement("div");
483	    el.className = "chat-system-msg";
484	    el.textContent = text;
485	    tabData.container.appendChild(el);
486	    scrollToBottom();
487	  }
488	
489	  function appendInfoBanner(tabData, text) {
490	    var el = document.createElement("div");
491	    el.className = "chat-info-banner";
492	    el.textContent = text;
493	    tabData.container.appendChild(el);
494	    scrollToBottom();
495	  }
496	
497	  function appendAuthBanner(tabData, msg) {
498	    var el = document.createElement("div");
499	    el.className = "chat-auth-banner";
500	    el.innerHTML =
501	      '<div class="chat-auth-text">' + escapeHtml(msg.message || "Authentication required") + "</div>" +
502	      '<button class="chat-auth-retry">Retry</button>';
503	    el.querySelector(".chat-auth-retry").addEventListener("click", function () {
504	      if (tabData.ws && tabData.ws.readyState === WebSocket.OPEN) {
505	        tabData.ws.send(JSON.stringify({ type: "retry" }));
506	        el.parentNode.removeChild(el);
507	      }
508	    });
509	    tabData.container.appendChild(el);
510	    scrollToBottom();
511	  }
512	
513	  // --- Input Handling ---
514	
515	  function sendUserMessage() {
516	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
517	    var tab = chatTabs[activeChatTabId];
518	    if (tab.streaming) return;
519	
520	    var text = $chatInput.value.trim();
521	    if (!text) return;
522	    $chatInput.value = "";
523	    $chatInput.style.height = "auto";
524	
525	    appendUserBubble(tab, text);
526	
527	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
528	      tab.ws.send(JSON.stringify({ type: "user_message", text: text }));
529	      tab.streaming = true;
530	      updateInputState();
531	    }
532	  }
533	
534	  function updateInputState() {
535	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
536	    var streaming = tab && tab.streaming;
537	    $chatInput.disabled = streaming;
538	    $chatSend.disabled = streaming;
539	    $chatInput.placeholder = streaming ? "Waiting for response..." : "Send a message...";
540	  }
541	
542	  // Auto-grow textarea
543	  $chatInput.addEventListener("input", function () {
544	    this.style.height = "auto";
545	    this.style.height = Math.min(this.scrollHeight, 150) + "px";
546	  });
547	
548	  // Enter to send, Shift+Enter for newline
549	  $chatInput.addEventListener("keydown", function (e) {
550	    if (e.key === "Enter" && !e.shiftKey) {
551	      e.preventDefault();
552	      sendUserMessage();
553	    }
554	  });
555	
556	  $chatSend.addEventListener("click", sendUserMessage);
557	
558	  $chatClose.addEventListener("click", function () {
559	    // Close all tabs
560	    Object.keys(chatTabs).forEach(function (tabId) {
561	      var tab = chatTabs[tabId];
562	      if (tab.ws && tab.ws.readyState === WebSocket.OPEN) tab.ws.close();
563	      if (tab.container && tab.container.parentNode) tab.container.parentNode.removeChild(tab.container);
564	    });
565	    chatTabs = {};
566	    activeChatTabId = null;
567	    $chatPanel.classList.add("hidden");
568	    document.body.classList.remove("chat-open");
569	    renderChatTabs();
570	  });
571	
572	  // View toggle — switch to terminal
573	  $viewToggle.addEventListener("click", function () {
574	    var mode = localStorage.getItem("ak-view-mode") === "terminal" ? "chat" : "terminal";
575	    localStorage.setItem("ak-view-mode", mode);
576	    $viewToggle.textContent = mode === "terminal" ? "Chat" : "TTY";
577	  });
578	
579	  // --- Public API (called from app.js) ---
580	
581	  window.AgentChat = {
582	    openChat: function (session) {
583	      // Check for existing tab with same session
584	      var ids = Object.keys(chatTabs);
585	      for (var i = 0; i < ids.length; i++) {
586	        if (chatTabs[ids[i]].sessionId === session.id) {
587	          switchChatTab(ids[i]);
588	          return;
589	        }
590	      }
591	      var agent = session.source || "claude";
592	      var title = session.summary || session.id.substring(0, 8);
593	      createChatTab(title, agent, session.cwd, session.id, session.summary);
594	    },
595	
596	    openNewChat: function (cwd) {
597	      var agent = localStorage.getItem("ak-default-agent") || "claude";
598	      var displayName = cwd.split("/").filter(Boolean).pop() || cwd;
599	      createChatTab("New: " + displayName, agent, cwd, null, null);
600	    },
601	  };
602	})();
